import { css } from '@emotion/core';
import styled from '@emotion/styled';
import { Anchor } from 'components';
import { colors, media, typography } from 'core';
import React, { FC, useState } from 'react';

import { CardProps, ContainerProps } from './props';

const RelevantTopicContainer = styled.div<ContainerProps>`
  ${(props) =>
    css`
      border-bottom: ${props.onHover ? '0px' : '1px'};
      border-radius: ${props.onHover ? '4px' : '0px'};
      border-bottom-style: solid;
      border-bottom-color: ${colors.variants.Neutral.LightGrey};
      background-color: ${props.onHover ? colors.variants.Brand.Purple : null};
      color: ${props.onHover ? colors.variants.Neutral.White : colors.variants.Neutral.Black};
      padding: 2rem 1rem;
      margin: 0.25rem 1.5rem;
      cursor: pointer;
    `}
`;

export const RelevantTopicCard: FC<CardProps> = (props: CardProps) => {
  // const [onHover, setOnHover] = useState<boolean>(false);
  //
  // const onHoverSetTrue = (): void => setOnHover(true);
  // const onHoverSetFalse = (): void => setOnHover(false);

  return (
    // <RelevantTopicContainer
    //   className="d-flex justify-content-center"
    //   onMouseOver={onHoverSetTrue}
    //   onMouseOut={onHoverSetFalse}
    //   onHover={onHover}
    // >
    <Anchor
      href={`/questions#${props.id}`}
      className="hover:tw-bg-purple-300  tw-px-8 tw-py-4 tw-border-b"
      // color={onHover ? colors.variants.Neutral.White : colors.variants.Neutral.Black}
      css={css(
        typography.styles.headingSemiBold17,
        media.queryStyled([
          typography.styles.headingSemiBold17,
          typography.styles.headingSemiBold17,
          typography.styles.headingSemiBold22,
        ]),
      )}
    >
      {props.title}
    </Anchor>
    // </RelevantTopicContainer>
  );
};
